def stream_generate(
    prompt: str,
    model: str = "llama3.1:8b",
    callback: Optional[callable] = None
) -> str:
    """Stream response tokens in real-time."""
    response = requests.post(
        f"{OLLAMA_URL}/api/generate",
        json={"model": model, "prompt": prompt, "stream": True},
        stream=True,
        timeout=120
    )

    full_response = ""
    for line in response.iter_lines():
        if line:
            data = json.loads(line)
            token = data.get("response", "")
            if callback:
                callback(token)
            else:
                print(token, end="", flush=True)
            full_response += token
            if data.get("done"):
                break

    return full_response

import ollama
stream = ollama.chat( model="llama3.1:8b", messages=[{"role": "user", "content": "Tell me a story"}], stream=True )
for chunk in stream: print(chunk["message"]["content"], end="", flush=True)

from dataclasses import dataclass, field
from typing import Optional, Any
import logging
import time
import requests

@dataclass
class OllamaConfig:
    model: str = "llama3.1:8b"
    temperature: float = 0.7
    top_p: float = 0.9
    top_k: int = 40
    num_ctx: int = 4096
    base_url: str = "http://localhost:11434"
    timeout: int = 120
    max_retries: int = 3

class OllamaService:
    """Production-ready Ollama service with error handling and retries."""

    def __init__(self, config: Optional[OllamaConfig] = None):
        self.config = config or OllamaConfig()
        self.logger = logging.getLogger(__name__)

    def is_available(self) -> bool:
        """Check if Ollama server is running."""
        try:
            response = requests.get(f"{self.config.base_url}/api/tags", timeout=5)
            return response.status_code == 200
        except Exception:
            return False

    def list_models(self) -> list[str]:
        """Get available models."""
        response = requests.get(f"{self.config.base_url}/api/tags", timeout=10)
        response.raise_for_status()
        return [m["name"] for m in response.json().get("models", [])]

    def _make_request(self, endpoint: str, payload: dict) -> dict:
        """Make request with exponential backoff retries."""
        last_error = None
        for attempt in range(self.config.max_retries):
            try:
                response = requests.post(
                    f"{self.config.base_url}{endpoint}",
                    json=payload,
                    timeout=self.config.timeout
                )
                response.raise_for_status()
                return response.json()
            except requests.exceptions.Timeout as e:
                last_error = e
                self.logger.warning(f"Timeout on attempt {attempt + 1}/{self.config.max_retries}")
                time.sleep(2 ** attempt)
            except requests.exceptions.RequestException as e:
                last_error = e
                self.logger.warning(f"Request failed on attempt {attempt + 1}: {e}")
                time.sleep(2 ** attempt)
        raise last_error

    def generate(self, prompt: str, system: str = "", **kwargs) -> dict[str, Any]:
        """Generate completion with metrics."""
        options = {
            "temperature": kwargs.get("temperature", self.config.temperature),
            "top_p": kwargs.get("top_p", self.config.top_p),
            "top_k": kwargs.get("top_k", self.config.top_k),
            "num_ctx": kwargs.get("num_ctx", self.config.num_ctx)
        }
        start_time = time.time()
        data = self._make_request("/api/generate", {
            "model": kwargs.get("model", self.config.model),
            "prompt": prompt,
            "system": system,
            "stream": False,
            "options": options
        })
        elapsed = time.time() - start_time
        return {
            "content": data["response"],
            "model": data["model"],
            "done": data["done"],
            "total_duration_ms": data.get("total_duration", 0) / 1_000_000,
            "eval_count": data.get("eval_count", 0),
            "tokens_per_second": data.get("eval_count", 0) / elapsed if elapsed > 0 else 0
        }

    def chat(self, messages: list[dict], tools: Optional[list] = None, **kwargs) -> dict[str, Any]:
        """Chat completion with optional tool support."""
        payload = {
            "model": kwargs.get("model", self.config.model),
            "messages": messages,
            "stream": False,
            "options": {
                "temperature": kwargs.get("temperature", self.config.temperature),
                "num_ctx": kwargs.get("num_ctx", self.config.num_ctx)
            }
        }
        if tools:
            payload["tools"] = tools
        data = self._make_request("/api/chat", payload)
        return {
            "content": data["message"]["content"],
            "role": data["message"]["role"],
            "tool_calls": data["message"].get("tool_calls"),
            "model": data["model"]
        }

    def pull_model(self, model: str) -> bool:
        """Pull a model from Ollama library with progress logging."""
        try:
            response = requests.post(
                f"{self.config.base_url}/api/pull",
                json={"name": model},
                stream=True,
                timeout=3600  # 1 hour for large models
            )
            for line in response.iter_lines():
                if line:
                    data = json.loads(line)
                    status = data.get("status", "")
                    self.logger.info(f"Pulling {model}: {status}")
                    if status == "success":
                        return True
            return False
        except Exception as e:
            self.logger.error(f"Failed to pull {model}: {e}")
            return False

from dataclasses import dataclass, field
from typing import Optional
import os

@dataclass
class OllamaConfig:
    """Ollama configuration with environment variable support."""

    # Server
    base_url: str = field(
        default_factory=lambda: os.getenv("OLLAMA_URL", "http://localhost:11434")
    )
    timeout: int = field(
        default_factory=lambda: int(os.getenv("OLLAMA_TIMEOUT", "120"))
    )
    max_retries: int = 3

    # Default model
    model: str = field(
        default_factory=lambda: os.getenv("OLLAMA_MODEL", "llama3.1:8b")
    )

    # Generation parameters
    temperature: float = 0.7
    top_p: float = 0.9
    top_k: int = 40
    num_ctx: int = 4096
    repeat_penalty: float = 1.1

    # Tool calling
    tool_model: str = field(
        default_factory=lambda: os.getenv("OLLAMA_TOOL_MODEL", "llama3.1:8b")
    )
    tool_ctx: int = 32768

    # Embedding
    embed_model: str = field(
        default_factory=lambda: os.getenv("OLLAMA_EMBED_MODEL", "nomic-embed-text")
    )

    # Vision
    vision_model: str = field(
        default_factory=lambda: os.getenv("OLLAMA_VISION_MODEL", "llava:7b")
    )

    @classmethod
    def for_coding(cls) -> "OllamaConfig":
        return cls(model="qwen2.5-coder:7b", temperature=0.2, num_ctx=16384, repeat_penalty=1.0)

    @classmethod
    def for_creative(cls) -> "OllamaConfig":
        return cls(temperature=0.9, top_p=0.95, top_k=100, num_ctx=8192, repeat_penalty=1.2)

    @classmethod
    def for_analysis(cls) -> "OllamaConfig":
        return cls(temperature=0.2, top_p=0.9, num_ctx=8192)
